const q   = $input.first().json.query || {};
const qid = (q.id  || '').toString().trim();
const id  = /^\d+$/.test(qid) && qid.length < 8 ? parseInt(qid) : 0;
const no  = (q.no  || (!id ? qid : '')).replace(/'/g, "''").trim();

if (!id && !no) return [{ json: { error: 'id or no required' } }];

const where = id ? `c.id = ${id}` : `c.complaintno = '${no}'`;

const sqlMain = `SELECT c.id, c.complaintno, c.productname, c.producttype, c.vendorname, c.contract_type, c.productlocation, c.natureofproblem, c.typeofcomplaint, c.tat, c.created, cs.storecode, cs.storename, cs.storecity AS city, cs.storeregion AS region, cs.statename AS state, cs.empcode, cs.empname, cs.empmobileno, cs.empdesignation, cs.managername, cs.managermobileno, cs.asmname, cs.asmmobileno, cs.fmname, cs.fmemail, cs.fmmobileno, cs.sourceofcomplaints, cs.sourceofctxnid, cs.sourceofcsubject, ve.closuredate AS edc, ve.escalationlevel, ve.ticketno AS vendor_ticketno, DATEDIFF(CURDATE(), ve.closuredate) AS days_overdue, cl.status AS current_status FROM vmm_complaints c LEFT JOIN vmm_complaintstores cs ON cs.id = c.storerefid LEFT JOIN vmm_vendorescalations ve ON ve.id = (SELECT MAX(id) FROM vmm_vendorescalations WHERE complaintid = c.id) LEFT JOIN vmm_complaintlogs cl ON cl.id = (SELECT MAX(id) FROM vmm_complaintlogs WHERE complaintid = c.id) WHERE ${where} AND c.is_deleted = 'No' LIMIT 1`;

const sqlLogs = id
  ? `SELECT id, remarks, status, uid, created FROM vmm_complaintlogs WHERE complaintid = ${id} AND is_deleted = 'No' ORDER BY created DESC`
  : `SELECT l.id, l.remarks, l.status, l.uid, l.created FROM vmm_complaintlogs l INNER JOIN vmm_complaints c ON c.id = l.complaintid WHERE c.complaintno = '${no}' AND l.is_deleted = 'No' ORDER BY l.created DESC`;

const sqlEsc = id
  ? `SELECT id, escalationlevel, ticketno, closuredate AS edc, created FROM vmm_vendorescalations WHERE complaintid = ${id} ORDER BY created ASC`
  : `SELECT ve.id, ve.escalationlevel, ve.ticketno, ve.closuredate AS edc, ve.created FROM vmm_vendorescalations ve INNER JOIN vmm_complaints c ON c.id = ve.complaintid WHERE c.complaintno = '${no}' ORDER BY ve.created ASC`;

return [{ json: { sqlMain, sqlLogs, sqlEsc } }];

const main = $('CmplDetail Fetch Main').all().map(i => i.json);
const logs = $('CmplDetail Fetch Logs').all().map(i => i.json);
const escs = $('CmplDetail Fetch Esc').all().map(i => i.json);

if (!main.length || !main[0].id) return [{ json: { success: false, message: 'Complaint not found' } }];

const c = main[0];
const callLogs  = logs.filter(l => (l.remarks || '').toLowerCase().includes('source: call'));
const emailLogs = logs.filter(l => (l.remarks || '').toLowerCase().includes('source: e-mail'));

return [{ json: {
  success: true,
  complaint: c,
  logs,
  escalations: escs,
  stats: {
    total: logs.length,
    calls: callLogs.length,
    emails: emailLogs.length
  }
} }];
